// PrepareCallOpts builds common SDK call options from CLI flags.
// Parses --header flags into operations.WithSetHeaders options.
// Server resolution and skip-deserialization are handled per-operation.
func PrepareCallOpts(cmd *cobra.Command) ([]operations.Option, error) {
	var opts []operations.Option
	if hdrs, _ := flagutil.GetStringArrayFlag(cmd, "header"); len(hdrs) > 0 {
		headerMap := make(map[string]string, len(hdrs))
		for _, h := range hdrs {
			k, v, ok := strings.Cut(h, ":")
			if !ok {
				return nil, fmt.Errorf("invalid header format %q: expected \"Key: Value\"", h)
			}
			headerMap[strings.TrimSpace(k)] = strings.TrimSpace(v)
		}
		opts = append(opts, operations.WithSetHeaders(headerMap))
	}
	return opts, nil
}

// ValidateGlobalServerIndex validates the --server flag as an integer index
// in range [0, count). Provides clear error messages for invalid values.
// The actual server application happens in client.NewClient via sdk.WithServerIndex
// (which handles server URL template variable resolution).
func ValidateGlobalServerIndex(cmd *cobra.Command, count int) error {
	serverFlag, _ := flagutil.GetStringFlag(cmd, "server")
	if serverFlag == "" {
		return nil
	}
	idx, err := strconv.Atoi(serverFlag)
	if err != nil {
		return fmt.Errorf("invalid server index %q: must be an integer (0-%d)", serverFlag, count-1)
	}
	if idx < 0 || idx >= count {
		return fmt.Errorf("server index %d out of range (0-%d)", idx, count-1)
	}
	return nil
}

// ValidateGlobalServerName validates the --server flag against a named server map.
// The actual server application happens in client.NewClient via sdk.WithServer.
func ValidateGlobalServerName(cmd *cobra.Command, validNames map[string]string) error {
	serverFlag, _ := flagutil.GetStringFlag(cmd, "server")
	if serverFlag == "" {
		return nil
	}
	if _, ok := validNames[serverFlag]; !ok {
		return fmt.Errorf("unknown server %q", serverFlag)
	}
	return nil
}

