// tryReadRawBody attempts to read the raw HTTP response body from the response
// envelope. Returns the body bytes if the body was unread (skip-deserialization
// was active), or nil if the body was already consumed (normal deserialization).
func tryReadRawBody(res interface{}) []byte {
	httpRes := extractHTTPResponse(res)
	if httpRes == nil || httpRes.Body == nil {
		return nil
	}
	rawBody, err := io.ReadAll(httpRes.Body)
	httpRes.Body.Close()
	if err != nil || len(rawBody) == 0 {
		return nil
	}
	return rawBody
}

// derefToStruct dereferences pointer/interface values and validates the result
// is a struct. Returns the dereferenced value and true, or a zero Value and false.
func derefToStruct(v reflect.Value) (reflect.Value, bool) {
	if v.Kind() == reflect.Ptr {
		if v.IsNil() {
			return reflect.Value{}, false
		}
		v = v.Elem()
	}
	if v.Kind() != reflect.Struct {
		return reflect.Value{}, false
	}
	return v, true
}

// extractHTTPResponse extracts the *http.Response from a response envelope.
// Supports envelope-http format (HTTPMeta.Response) and flat format (RawResponse).
func extractHTTPResponse(res interface{}) *http.Response {
	if res == nil {
		return nil
	}
	v, ok := derefToStruct(reflect.ValueOf(res))
	if !ok {
		return nil
	}
	// envelope-http: HTTPMeta.Response
	httpMeta := v.FieldByName("HTTPMeta")
	if httpMeta.IsValid() && httpMeta.Kind() == reflect.Struct {
		resp := httpMeta.FieldByName("Response")
		if resp.IsValid() && !resp.IsNil() {
			if r, ok := resp.Interface().(*http.Response); ok {
				return r
			}
		}
	}
	// flat format fallback: RawResponse
	rawResp := v.FieldByName("RawResponse")
	if rawResp.IsValid() && !rawResp.IsNil() {
		if r, ok := rawResp.Interface().(*http.Response); ok {
			return r
		}
	}
	return nil
}

// extractResultContent extracts the meaningful result field from a response envelope.
// SDK response structs contain envelope fields (HTTPMeta or ContentType/StatusCode/RawResponse)
// plus one or more result fields. This function returns the first non-nil result field,
// stripping the envelope so CLI output shows only the data users care about.
func extractResultContent(res interface{}) interface{} {
	if res == nil {
		return nil
	}
	v, ok := derefToStruct(reflect.ValueOf(res))
	if !ok {
		return res
	}

	for i := 0; i < v.NumField(); i++ {
		field := v.Type().Field(i)
		if !field.IsExported() {
			continue
		}
		if isEnvelopeField(field) {
			continue
		}
		fieldVal := v.Field(i)
		// Skip function fields (e.g., pagination Next closure)
		if fieldVal.Kind() == reflect.Func {
			continue
		}
		// Skip nil pointer/interface fields
		if (fieldVal.Kind() == reflect.Ptr || fieldVal.Kind() == reflect.Interface) && fieldVal.IsNil() {
			continue
		}
		return fieldVal.Interface()
	}

	// No result field found (status-code-only response)
	return nil
}

// isEnvelopeField returns true for standard response envelope fields that should
// be stripped from CLI output.
func isEnvelopeField(field reflect.StructField) bool {
	switch field.Type {
	case reflect.TypeOf((*http.Response)(nil)):
		return true
	}
	switch field.Name {
	case "ContentType", "StatusCode", "HTTPMeta", "Headers":
		return true
	}
	return false
}

// extractErrorBody extracts the Body string field from an error via reflection.
func extractErrorBody(err error) string {
	v, ok := derefToStruct(reflect.ValueOf(err))
	if !ok {
		return ""
	}
	bodyField := v.FieldByName("Body")
	if bodyField.IsValid() && bodyField.Kind() == reflect.String {
		return bodyField.String()
	}
	return ""
}

// extractErrorStatusCode extracts the StatusCode int field from an error via reflection.
func extractErrorStatusCode(err error) int {
	v, ok := derefToStruct(reflect.ValueOf(err))
	if !ok {
		return 0
	}
	field := v.FieldByName("StatusCode")
	if field.IsValid() && field.CanInt() {
		return int(field.Int())
	}
	return 0
}

func isValidJSON(s string) bool {
	var js json.RawMessage
	return json.Unmarshal([]byte(s), &js) == nil
}

// wantsHeaders returns true when --include-headers is set.
func wantsHeaders(cmd *cobra.Command) bool {
	includeHeaders, _ := flagutil.GetBoolFlag(cmd, "include-headers")
	return includeHeaders
}

// extractResponseHeaders extracts HTTP response headers from a response envelope.
// Uses extractHTTPResponse to get all HTTP headers (not just spec-defined ones).
func extractResponseHeaders(res interface{}) http.Header {
	httpRes := extractHTTPResponse(res)
	if httpRes == nil {
		return nil
	}
	return httpRes.Header
}

// extractErrorResponseHeaders extracts HTTP response headers from an SDK error.
// Error types store *http.Response in a RawResponse field.
func extractErrorResponseHeaders(err error) http.Header {
	if err == nil {
		return nil
	}
	v, ok := derefToStruct(reflect.ValueOf(err))
	if !ok {
		return nil
	}
	rawResp := v.FieldByName("RawResponse")
	if rawResp.IsValid() && !rawResp.IsNil() {
		if r, ok := rawResp.Interface().(*http.Response); ok && r != nil {
			return r.Header
		}
	}
	return nil
}

// flattenHeaders converts http.Header (map[string][]string) to map[string]interface{}
// for JSON output. Single-value headers are flattened to strings; multi-value headers
// remain as arrays. Key order is not guaranteed; callers relying on deterministic output
// should sort separately (json.Marshal sorts map keys; printResponseHeadersPretty sorts explicitly).
func flattenHeaders(headers http.Header) map[string]interface{} {
	if len(headers) == 0 {
		return nil
	}
	result := make(map[string]interface{}, len(headers))
	for k, v := range headers {
		if len(v) == 1 {
			result[k] = v[0]
		} else {
			result[k] = v
		}
	}
	return result
}

// injectHeaders merges flattened response headers into a parsed JSON data structure.
// If data is a map, adds _response_headers as a sibling key.
// If data is nil, returns just the headers.
// Otherwise wraps as {"_result": data, "_response_headers": headers}.
func injectHeaders(data interface{}, headers http.Header) interface{} {
	flat := flattenHeaders(headers)
	if flat == nil {
		return data
	}
	if data == nil {
		return map[string]interface{}{
			"_response_headers": flat,
		}
	}
	if m, ok := data.(map[string]interface{}); ok {
		m["_response_headers"] = flat
		return m
	}
	return map[string]interface{}{
		"_result":           data,
		"_response_headers": flat,
	}
}

// outputWithHeaders marshals content to JSON, parses it, injects headers,
// and outputs in the specified format. This is the common path for --include-headers
// in json, yaml, toon, and jq output modes.
